import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def read_sql(name):
    return (ROOT / "sql" / name).read_text(encoding="ascii")


def make_db():
    db = sqlite3.connect(":memory:")
    db.execute(
        """
        CREATE TABLE export_job (
            job_id INTEGER PRIMARY KEY,
            state TEXT NOT NULL CHECK (state IN ('queued', 'running', 'canceled', 'completed')),
            worker_id TEXT,
            result_uri TEXT
        )
        """
    )
    return db


def test_a_canceled_job_cannot_be_claimed_again():
    db = make_db()
    db.execute("INSERT INTO export_job VALUES (20, 'canceled', NULL, NULL)")

    cursor = db.execute(
        read_sql("claim_export_job.sql"),
        {"job_id": 20, "worker_id": "worker-a"},
    )

    assert cursor.rowcount == 0
    assert db.execute("SELECT state, worker_id FROM export_job").fetchone() == (
        "canceled",
        None,
    )


def test_a_queued_job_cannot_be_finished_without_a_claim():
    db = make_db()
    db.execute("INSERT INTO export_job VALUES (21, 'queued', NULL, NULL)")

    cursor = db.execute(
        read_sql("finish_export_job.sql"),
        {
            "job_id": 21,
            "worker_id": "worker-a",
            "result_uri": "exports/early.csv",
        },
    )

    assert cursor.rowcount == 0
    assert db.execute("SELECT state, worker_id, result_uri FROM export_job").fetchone() == (
        "queued",
        None,
        None,
    )


def test_rejected_interference_does_not_block_one_terminal_result():
    db = make_db()
    db.execute(
        "INSERT INTO export_job VALUES (22, 'running', 'worker-a', NULL)"
    )

    foreign = db.execute(
        read_sql("finish_export_job.sql"),
        {
            "job_id": 22,
            "worker_id": "worker-b",
            "result_uri": "exports/foreign.csv",
        },
    )
    owner = db.execute(
        read_sql("finish_export_job.sql"),
        {
            "job_id": 22,
            "worker_id": "worker-a",
            "result_uri": "exports/final.csv",
        },
    )
    replay = db.execute(
        read_sql("finish_export_job.sql"),
        {
            "job_id": 22,
            "worker_id": "worker-a",
            "result_uri": "exports/retry.csv",
        },
    )

    assert (foreign.rowcount, owner.rowcount, replay.rowcount) == (0, 1, 0)
    assert db.execute("SELECT state, worker_id, result_uri FROM export_job").fetchone() == (
        "completed",
        "worker-a",
        "exports/final.csv",
    )
